    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.ebs_profile.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }
}

resource "aws_iam_role" "ebs_role" {
  name = "ebs-bluegreen-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_instance_profile" "ebs_profile" {
  name = "ebs-bluegreen-profile"
  role = aws_iam_role.ebs_role.name
}

resource "aws_route53_zone" "app_zone" {
  name = "example.com"
}

resource "aws_route53_record" "app_record" {
  zone_id = aws_route53_zone.app_zone.zone_id
  name    = "app.example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.blue.cname
    zone_id                = aws_elastic_beanstalk_environment.blue.cname_zone_id
    evaluate_target_health = true
  }

  set_identifier = "blue"

  failover_routing_policy {
    type = "PRIMARY"
  }

  health_check_id = aws_route53_health_check.app_health.id
}

resource "aws_route53_record" "app_record_green" {
  zone_id = aws_route53_zone.app_zone.zone_id
  name    = "app.example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.green.cname
    zone_id                = aws_elastic_beanstalk_environment.green.cname_zone_id
    evaluate_target_health = true
  }

  set_identifier = "green"

  failover_routing_policy {
    type = "SECONDARY"
  }

  health_check_id = aws_route53_health_check.app_health.id
}

resource "aws_route53_health_check" "app_health" {
  health_check_config {
    type               = "HTTPS"
    resource_path      = "/health"
    fully_qualified_domain_name = "app.example.com"
    request_interval   = 30
    failure_threshold  = 3
  }
}

resource "aws_route53_record" "weighted_record" {
  zone_id = aws_route53_zone.app_zone.zone_id
  name    = "app.example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.blue.cname
    zone_id                = aws_elastic_beanstalk_environment.blue.cname_zone_id
    evaluate_target_health = true
  }

  set_identifier = "weighted"

  weighted_routing_policy {
    weight = 100 # Initially all traffic to blue
  }

  health_check_id = aws_route53_health_check.app_health.id
}

resource "aws_route53_record" "weighted_record_green" {
  zone_id = aws_route53_zone.app_zone.zone_id
  name    = "app.example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.green.cname
    zone_id                = aws_elastic_beanstalk_environment.green.cname_zone_id
    evaluate_target_health = true
  }

  set_identifier = "weighted-green"

  weighted_routing_policy {
    weight = 0 # Initially no traffic to green
  }

  health_check_id = aws_route53_health_check.app_health.id
}
