      phases:
        install:
          runtime-versions:
            python: 3.8
          commands:
            - echo "Installing dependencies..."
            - pip install -r requirements.txt
        build:
          commands:
            - echo "Building the application..."
            - python setup.py build
      artifacts:
        files:
