  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSCodeBuildServiceRole"
}

resource "aws_iam_role_policy_attachment" "cloudwatch_logs" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchLogsFullAccess"
}

resource "aws_iam_role_policy_attachment" "ecr_access" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEC2ContainerRegistryPowerUser"
}

resource "aws_codebuild_source_version" "github_source" {
  identifier    = "github-source-${random_id.suffix.hex}"
  region        = "us-east-1"
  git_clone_depth = 0
  git_submodules_config {
    fetch_submodules = true
  }
  authentication {
    type      = "GITHUB_OAUTH"
    token     = var.github_token # Replace with your GitHub OAuth token
  }
}

resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project-${random_id.suffix.hex}"
  description   = "Example CodeBuild Project"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = true

    environment_variable {
      name  = "SOURCE_REPO"
      value = "https://github.com/your-repo/your-project.git"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/example-codebuild-project-${random_id.suffix.hex}"
      stream_name = "build-log"
    }
    s3_logs {
      status = "DISABLED"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-repo/your-project.git"
    git_clone_depth = 1
    buildspec = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.8
          commands:
            - echo Installing source NPM packages...
            - npm install
        pre_build:
          commands:
            - echo Logging in to Amazon ECR...
            - aws --version
            - aws ecr get-login-password --region $AWS_DEFAULT_REGION | docker login --username AWS --password-stdin $AWS_ACCOUNT_ID.dkr.ecr.$AWS_DEFAULT_REGION.amazonaws.com
        build:
          commands:
            - echo Build started on `date`
            - echo Building the Docker image...
            - docker build -t $REPOSITORY_URI:latest .
            - docker tag $REPOSITORY_URI:latest $REPOSITORY_URI:$IMAGE_TAG
        post_build:
          commands:
            - echo Build completed on `date`
            - echo Pushing the Docker images...
            - docker push $REPOSITORY_URI:latest
            - docker push $REPOSITORY_URI:$IMAGE_TAG
      artifacts:
        files: '**/*'
      cache:
        paths: '/root/.npm/**/*'
    EOT
    }
}
```

