resource "aws_lex_bot" "pizza_order_bot" {
  name        = "pizza-order-bot-${random_id.suffix.hex}"
  description = "A Lex bot for ordering pizzas with natural language processing"

  idle_session_ttl_in_seconds = 300

  lifecycle {
    ignore_changes = [version]
  }

  # Define the bot's locale (English in this case)
  locale_settings {
    locale = "en_US"

    nlu_intent_confidence_threshold = 0.5
  }

  # Define the bot's child directed model
  child_directed = false

  # Define the bot's voice settings (optional)
  voice_settings {
    voice_id = "Joanna" # AWS Polly voice ID
  }

  # Define the bot's bot stream settings (optional)
  bot_stream_settings {
    enable_auto_fulfillment = true
    enable_auto_reprompt = true
  }

  # Define the bot's fulfillment configuration (optional)
  fulfillment_configuration {
    lambda_arn = aws_lambda_function.pizza_order_lambda.arn
  }

  # Define the bot's message groups (optional)
  message_groups {
    name = "pizza_order_messages"
    description = "Message group for pizza order bot"
  }

  # Define the bot's slot types (optional)
  slot_types {
    name = "pizza_size"
    description = "Slot type for pizza size"
    values {
      value = "small"
    }
    values {
      value = "medium"
    }
    values {
      value = "large"
    }
    values {
      value = "extra_large"
    }
  }

  slot_types {
    name = "pizza_type"
    description = "Slot type for pizza type"
    values {
      value = "cheese"
    }
    values {
      value = "pepperoni"
    }
    values {
      value = "vegetarian"
    }
    values {
      value = "hawaiian"
    }
  }

  slot_types {
    name = "delivery_address"
    description = "Slot type for delivery address"
    values {
      value = "123 Main St, Anytown, USA"
    }
  }

  # Define the bot's intents (optional)
  intent {
    name = "OrderPizza"
    sample_utterances = ["order a pizza", "I want to order a pizza", "pizza please"]
    fulfillment_activity {
      type = "ReturnIntent"
    }
  }

  intent {
    name = "CancelOrder"
    sample_utterances = ["cancel my order", "I want to cancel my order"]
    fulfillment_activity {
      type = "ReturnIntent"
    }
  }

  intent {
    name = "Help"
    sample_utterances = ["help", "how can I order a pizza?"]
    fulfillment_activity {
      type = "ReturnIntent"
    }
  }

  # Define the bot's slots (optional)
  slot {
    name = "size"
    slot_type_name = "pizza_size"
  }

  slot {
    name = "type"
    slot_type_name = "pizza_type"
  }

  slot {
    name = "address"
    slot_type_name = "delivery_address"
  }

  # Define the bot's fulfillment code (Lambda function)
}

resource "aws_lambda_function" "pizza_order_lambda" {
  function_name = "pizza-order-lambda-${random_id.suffix.hex}"
  runtime       = "nodejs14.x"
  handler       = "index.handler"
  role          = aws_iam_role.lambda_exec.arn
  s3_bucket     = aws_s3_bucket.lambda_bucket.bucket
  s3_key        = aws_s3_object.lambda_function.key

  environment {
    variables = {
      BOT_NAME = aws_lex_bot.pizza_order_bot.name
    }
  }
}

resource "aws_iam_role" "lambda_exec" {
  name = "lambda_exec_role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_s3_bucket" "lambda_bucket" {
  bucket = "pizza-order-lambda-bucket-${random_id.suffix.hex}"
}

resource "aws_s3_object" "lambda_function" {
  bucket = aws_s3_bucket.lambda_bucket.bucket
  key    = "pizza-order-lambda.zip"
  source = "path/to/pizza-order-lambda.zip" # Replace with the path to your Lambda function zip file
  etag   = filemd5("path/to/pizza-order-lambda.zip")
}

# Conclusion statement for the bot
output "conclusion_statement" {
  value = <<-EOT
    Congratulations! You have successfully created a Lex bot named "${aws_lex_bot.pizza_order_bot.name}"
    for ordering pizzas. This bot includes:

    - A Lambda function for fulfillment logic
    - Intents for ordering, canceling, and seeking help
    - Slot types for pizza size, type, and delivery address
    - Basic IAM roles and permissions for Lambda execution

    Next steps:
    1. Deploy the Lambda function code to the S3 bucket.
    2. Configure the Lex bot in the AWS Console to connect to your Lambda function.
    3. Test the bot using the Lex Console or integrate it into your application.
  EOT
}

