resource "aws_lex_bot" "kids_pizza_ordering_bot" {
  name        = "KidsPizzaOrderingBot-${random_id.suffix.hex}"
  description = "A Lex bot for kids to order pizzas with simple interactions"

  # Define the bot's locale (language)
  locale_settings {
    locale = "en_US"

    # Define the bot's voice settings
    nlu_intent_confidence_threshold = 0.5

    # Define the bot's fulfillment settings
    fulfillment_image_uri = "https://example.com/fulfillment-image.png"
    fulfillment_activity_timeout_in_seconds = 300

    # Define the bot's slot types
    slot_types {
      name = "PizzaSize"
      description = "The size of the pizza"
      value_eligibility {
        literal_values = ["small", "medium", "large"]
      }
    }

    slot_types {
      name = "Topping"
      description = "The toppings on the pizza"
      value_eligibility {
        literal_values = ["pepperoni", "cheese", "mushroom", "olives", "pineapple"]
      }
    }
  }

  # Define the bot's intents
  intent {
    name        = "OrderPizzaIntent"
    sample_utterances = ["order a pizza", "I want to order a pizza", "Let's get a pizza"]
    description = "Intent for ordering a pizza"
    sample_utterances_en_US = ["order a pizza", "I want to order a pizza", "Let's get a pizza"]
    fulfillment_activity_type = "Close"

    # Define the slots for this intent
    slot {
      name = "PizzaSize"
      slot_type_name = "PizzaSize"
    }

    slot {
      name = "Topping"
      slot_type_name = "Topping"
    }
  }

  intent {
    name        = "HelpIntent"
    sample_utterances = ["help", "what can you do?", "I need help"]
    description = "Intent for getting help"
    sample_utterances_en_US = ["help", "what can you do?", "I need help"]
    fulfillment_activity_type = "Close"
  }

  intent {
    name        = "CancelIntent"
    sample_utterances = ["cancel", "nevermind", "stop"]
    description = "Intent for canceling the order"
    sample_utterances_en_US = ["cancel", "nevermind", "stop"]
    fulfillment_activity_type = "Close"
  }

  # Define the bot's child directed settings
  child_directed = true

  # Define the bot's data privacy settings
  data_privacy {
    child_directed = true
    min_age_of_user_in_years = 13
  }
}

