  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_lexv2_intent" "greeting" {
  bot_id      = aws_lexv2_model.children_bot.id
  intent_name = "GreetingIntent"
  description = "Greeting intent for children"

  sample_utterances = ["hello", "hi", "hey", "greetings"]
}

resource "aws_lexv2_intent" "help" {
  bot_id      = aws_lexv2_model.children_bot.id
  intent_name = "HelpIntent"
  description = "Help intent for children"

  sample_utterances = ["help", "how can I help", "what can you do"]
}

resource "aws_lexv2_slot_type" "age_slot" {
  name        = "AgeSlot"
  description = "Slot type for age input"
  value_elimination_strategy = "ELIMINATE_ALL"
}

resource "aws_lexv2_slot_type" "topic_slot" {
  name        = "TopicSlot"
  description = "Slot type for topic input"
  value_elimination_strategy = "ELIMINATE_ALL"
}

resource "aws_lexv2_slot_type" "emotion_slot" {
  name        = "EmotionSlot"
  description = "Slot type for emotion input"
  value_elimination_strategy = "ELIMINATE_ALL"
}

resource "aws_lexv2_slot_type" "name_slot" {
  name        = "NameSlot"
  description = "Slot type for name input"
  value_elimination_strategy = "ELIMINATE_ALL"
}

resource "aws_lexv2_slot_type" "feeling_slot" {
  name        = "FeelingSlot"
  description = "Slot type for feeling input"
  value_elimination_strategy = "ELIMINATE_ALL"
  enum_value {
    value {
      name = "happy"
    }
    value {
      name = "sad"
    }
    value {
      name = "angry"
    }
    value {
      name = "scared"
    }
    value {
      name = "confused"
    }
  }
}

resource "aws_lexv2_slot_type" "situation_slot" {
  name        = "SituationSlot"
  description = "Slot type for situation input"
  value_elimination_strategy = "ELIMINATE_ALL"
}

resource "aws_lexv2_intent" "feeling_help" {
  bot_id      = aws_lexv2_model.children_bot.id
  intent_name = "FeelingHelpIntent"
  description = "Intent for helping children with their feelings"

  sample_utterances = [
    "I feel {feeling}",
    "I am {feeling}",
    "I am feeling {feeling}",
    "I feel {feeling} about {topic}"
  ]

  slot_types = [
    aws_lexv2_slot_type.feeling_slot.name,
    aws_lexv2_slot_type.topic_slot.name
  ]
}

resource "aws_lexv2_intent" "situation_help" {
  bot_id      = aws_lexv2_model.children_bot.id
  intent_name = "SituationHelpIntent"
  description = "Intent for helping children with specific situations"

  sample_utterances = [
    "I am in a {situation}",
    "I don't know what to do in a {situation}",
    "I need help with {situation}"
  ]

  slot_types = [
    aws_lexv2_slot_type.situation_slot.name
  ]
}

resource "aws_lexv2_intent" "name_help" {
  bot_id      = aws_lexv2_model.children_bot.id
  intent_name = "NameHelpIntent"
  description = "Intent for personalized help"

  sample_utterances = [
    "{name}, I need help",
    "Hello, my name is {name}, I need help",
    "{name} needs help"
  ]

  slot_types = [
    aws_lexv2_slot_type.name_slot.name
  ]
}

