resource "aws_connect_bot_association" "example" {
  bot_id          = "your-bot-id" # Replace with your Amazon Connect bot ID
  instance_id     = "your-instance-id" # Replace with your Amazon Connect instance ID
  phone_number_id = "your-phone-number-id" # Replace with your Amazon Connect phone number ID

