      log_stream_name = "firehose-opensearch-logs"
    }

    error_output_prefix = "firehose-errors/"
    processing_configuration {
      enabled = "true"

      processors {
        type = "Lambda"
        parameters {
          lambda_arn    = aws_lambda_function.opensearch_processor.arn
          role_arn      = aws_iam_role.lambda_exec.arn
        }
      }
    }
  }

  tags = {
    Name = "OpenSearch-Destination-Firehose"
  }
}

