}

resource "aws_kinesis_firehose_delivery_stream" "opensearch_destination" {
  name        = "opensearch-delivery-${random_id.suffix.hex}"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_opensearch.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
    prefix     = "firehose-data/"

    buffering_hints {
      size    = 5
      interval = 300
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose_logs.name
      log_stream_name = "firehose-opensearch-logs"
    }

    error_output_prefix = "firehose-errors/"
    processing_configuration {
      enabled = "true"

      processors {
        type = "Lambda"
        parameters {
          lambda_arn    = aws_lambda_function.opensearch_processor.arn
          role_arn      = aws_iam_role.lambda_exec.arn
        }
      }
    }
  }

  tags = {
    Name = "OpenSearch-Destination-Firehose"
  }
}

resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "firehose-bucket-${random_id.suffix.hex}"
}

resource "aws_iam_role" "firehose_opensearch" {
  name = "firehose-opensearch-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "firehose.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_s3_access" {
  role       = aws_iam_role.firehose_opensearch.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_cloudwatch_log_group" "firehose_logs" {
  name = "/aws/kinesisfirehose/firehose-opensearch-logs"
}

resource "aws_lambda_function" "opensearch_processor" {
  function_name = "opensearch-processor"
  runtime       = "python3.8"
  handler       = "lambda_function.lambda_handler"
  role          = aws_iam_role.lambda_exec.arn
  s3_bucket     = aws_s3_bucket.lambda_bucket.name
  s3_key        = aws_s3_bucket_object.lambda_function.key

  environment {
    variables = {
      OPENSEARCH_ENDPOINT = "https://your-opensearch-endpoint:9200"
      OPENSEARCH_INDEX    = "firehose-data"
    }
  }
}

resource "aws_iam_role" "lambda_exec" {
  name = "lambda-exec-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_opensearch_access" {
  name = "lambda-opensearch-access"
  role = aws_iam_role.lambda_exec.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect = "Allow"
      Action = [
        "es:ESHttpPost",
        "es:ESHttpPut"
      ]
      Resource = "arn:aws:es:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:domain/${var.opensearch_domain_name}/*"
    }]
  })
}

resource "aws_s3_bucket" "lambda_bucket" {
  bucket = "lambda-bucket-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_object" "lambda_function" {
  bucket = aws_s3_bucket.lambda_bucket.id
  key    = "opensearch_processor.zip"
  source = "path/to/your/lambda_function.zip"
}

