resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "firehose-opensearch-bucket-${random_id.suffix.hex}"
  force_destroy = true
}

resource "aws_kms_key" "firehose_key" {
  description = "KMS key for Firehose encryption"
  policy = data.aws_iam_policy_document.firehose_kms_policy.json
}

resource "aws_iam_role" "firehose_opensearch_role" {
  name = "firehose-opensearch-role-${random_id.suffix.hex}"
  assume_role_policy = data.aws_iam_policy_document.firehose_assume_role.json
}

resource "aws_iam_role_policy" "firehose_opensearch_policy" {
  name = "firehose-opensearch-policy"
  role = aws_iam_role.firehose_opensearch_role.id
  policy = data.aws_iam_policy_document.firehose_opensearch_policy.json
}

resource "aws_cloudwatch_log_group" "firehose_logs" {
  name = "/aws/kinesisfirehose/firehose-opensearch-${random_id.suffix.hex}"
}

resource "aws_opensearch_domain" "example" {
  domain_name    = "firehose-opensearch-domain-${random_id.suffix.hex}"
  engine_version = "OpenSearch_1.3"

  cluster_config {
    instance_type = "t3.small.search"
    instance_count = 1
    zone_awareness_enabled = false
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
    volume_type = "gp2"
  }

  vpc_options {
    security_group_ids = [aws_security_group.opensearch_sg.id]
    subnet_ids         = [aws_subnet.opensearch_subnet.id]
  }

  encrypt_at_rest {
    enabled = true
  }

  node_to_node_encryption {
    enabled = true
  }

  advanced_options = {
    "rest.action.multi.allow_explicit_index" = "true"
  }

  domain_endpoint_options {
    enforce_https       = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }
}

resource "aws_security_group" "opensearch_sg" {
  name        = "firehose-opensearch-sg-${random_id.suffix.hex}"
  description = "Security group for OpenSearch"
  vpc_id      = aws_vpc.opensearch_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_vpc" "opensearch_vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "opensearch_subnet" {
  vpc_id     = aws_vpc.opensearch_vpc.id
  cidr_block = "10.0.1.0/24"
}

data "aws_iam_policy_document" "firehose_assume_role" {
  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["firehose.amazonaws.com"]
    }
  }
}

data "aws_iam_policy_document" "firehose_kms_policy" {
  statement {
    sid    = "Enable IAM User Permissions"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["*"]
    }
    actions   = ["kms:*"]
    resources = ["*"]
  }
}

data "aws_iam_policy_document" "firehose_opensearch_policy" {
  statement {
    effect = "Allow"
    actions = [
      "s3:PutObject",
      "s3:GetObject",
      "s3:AbortMultipartUpload",
      "s3:ListMultipartUploadParts"
    ]
    resources = [
      "${aws_s3_bucket.firehose_bucket.arn}/*"
    ]
  }

  statement {
    effect = "Allow"
    actions = [
      "logs:PutLogEvents",
      "logs:CreateLogGroup",
      "logs:CreateLogStream"
    ]
    resources = [
      "${aws_cloudwatch_log_group.firehose_logs.arn}:*"
    ]
  }

  statement {
    effect = "Allow"
    actions = [
      "opensearch:ESHttpPost",
      "opensearch:ESHttpPut"
    ]
    resources = [
      "${aws_opensearch_domain.example.endpoint}"
    ]
  }
}
