  application_version {
    id     = "1"
    name   = "app-version-1"
    code_location {
      s3_location {
        bucket_arn = aws_s3_bucket.kinesis_analytics_bucket.arn
        file_key   = "sql-app-code.zip"
        version_id = "latest"
      }
    }
  }
}

