  zone_id = aws_route53_zone.primary.zone_id
  name    = "service.example53.com"
  type    = "A"
  ttl     = "60"
  records = ["192.0.2.102"]

  set_identifier = "EU Frankfurt"

  latency_routing_policy {
    region = "eu-central-1"
  }
