Here's a simplified and correct version of the Terraform configuration for a Route 53 least-congested routing policy:

```hcl
resource "aws_route53_zone" "primary" {
  name = "primary.example.com"
}

resource "aws_lb" "app_lb" {
  name               = "app-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb.id]
  subnets            = [
    aws_subnet.us_east_1a.id,
    aws_subnet.eu_central_1a.id
  ]
}

resource "aws_lb_target_group" "app_tg" {
  name     = "app-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.example.id

  health_check {
    path                = "/health"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 3
    matcher             = "200-299"
  }
}

resource "aws_route53_record" "app_record" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.primary.example.com"
  type    = "A"

  alias {
    zone_id               = aws_lb.app_lb.zone_id
    name                  = aws_lb.app_lb.dns_name
    evaluate_target_health = true
  }

  set_identifier = "least-congested"

  failover_routing_policy {
    region = "us-east-1"
  }

  failover_routing_policy {
    region = "eu-central-1"
  }

  routing_policy = "least-congested"
}

resource "aws_route53_health_check" "app_health_check" {
  name          = "app-health-check"
  resource_path = "/health"
  type          = "HTTPS"
  fully_qualified_domain_name = aws_lb.app_lb.dns_name
  request_interval = 30
  failure_threshold = 3
}

resource "aws_route53_record" "app_health_check_record" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "healthcheck.app.primary.example.com"
  type    = "CNAME"
  ttl     = 60
  records = [aws_route53_health_check.app_health_check.id]
}
```

