```hcl
resource "aws_iam_policy" "example" {
  name        = "example"
  description = "Access policy for EKS cluster with namespace scope"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "eks:*",
          "ec2:Describe*",
          "iam:GetRole",
          "iam:GetRolePolicy",
          "iam:ListRolePolicies"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "eks:DescribeCluster",
          "eks:ListClusters"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "eks:AccessKubernetesApi"
        ]
        Resource = [
          "arn:aws:eks:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:cluster/${var.cluster_name}"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "eks:DescribeCluster"
        ]
        Resource = [
          "arn:aws:eks:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:cluster/${var.cluster_name}"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "eks:DescribeAddonVersion"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "eks:ListAddons"
        ]
        Resource = [
          "arn:aws:eks:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:cluster/${var.cluster_name}"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "eks:ListClusters"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "example" {
  role       = var.principal_arn
  policy_arn = aws_iam_policy.example.arn
}

resource "aws_eks_cluster_policy" "example" {
  cluster_name           = var.cluster_name
  policy_arn             = aws_iam_policy.example.arn
  namespace_selector {
    namespace = var.namespace
    label_selector {
      match_labels = {
        "access-level" = "restricted"
      }
    }
  }
}

variable "cluster_name" {
  description = "Name of the EKS cluster"
  type        = string
}

variable "principal_arn" {
  description = "ARN of the principal (e.g., IAM role or user) to attach the policy to"
  type        = string
}

variable "namespace" {
  description = "Namespace to restrict access to"
  type        = string
}

data "aws_region" "current" {}

data "aws_caller_identity" "current" {}
```

