              echo "${aws_efs_file_system.shared_storage.dns_name}:/ /mnt/shared-storage nfs4 nfsvers=4.1,rsize=1048576,wsize=1048576,hard,timeo=600,retrans=2 0 0" >> /etc/fstab
              EOF

  tags = {
    Name = "private-ec2-instance-a"
  }
}

