resource "aws_redshift_cluster" "example" {
  cluster_identifier          = "redshift-cluster-${random_id.suffix.hex}"
  database_name               = "devdb"
  master_username             = "admin"
  master_password             = random_password.db.result
  node_type                   = "dc2.large"
  cluster_type                = "multi-node"
  number_of_nodes            = 2
  publicly_accessible         = true
  skip_final_snapshot         = true
  encrypted                   = true
  vpc_security_group_ids      = [aws_security_group.redshift_sg.id]
  cluster_subnet_group_name   = aws_redshift_subnet_group.example.name
  iam_roles                   = [aws_iam_role.redshift_role.arn]
}

resource "random_password" "db" {
  length  = 16
  special = false
}

resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow inbound traffic to Redshift cluster"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Adjust this for production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_redshift_subnet_group" "example" {
  name       = "redshift-subnet-group"
  subnet_ids = var.subnet_ids
}

resource "aws_iam_role" "redshift_role" {
  name = "redshift-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "redshift_s3_access" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}
