        min_write_capacity     = 5
        max_write_capacity     = 20
        target_write_capacity_utilization = 70
      }
    }

    time_to_live_attribute_name = "expiration_time"
    stream_specification {
      stream_enabled = true
      stream_view_type = "NEW_AND_OLD_IMAGES"
    }
  }
}

