resource "aws_security_group" "notebook_sg" {
  name        = "sagemaker-notebook-sg"
  description = "Allow SSH and SageMaker traffic"
  vpc_id      = "<YOUR_VPC_ID>"

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "tcp"
