  name = "data-processing-pipeline-${random_id.suffix.hex}"

  pipeline_definition = jsonencode({
    "PipelineName" : "DataProcessingPipeline",
    "RoleArn" : aws_iam_role.sagemaker_pipeline_role.arn,
    "ExecutionVariables" : {
      "DataSourceS3Uri" : "s3://your-data-bucket/path/to/data"
    },
    "PipelineDefinition" : {
      "Nodes" : [
        {
          "NodeName" : "DataProcessingNode",
          "Properties" : {
            "ProcessingInputConfig" : [
              {
                "InputName" : "input",
                "SourceInputConfig" : {
                  "S3InputConfig" : {
                    "S3Uri" : "s3://your-data-bucket/path/to/data",
                    "S3DataType" : "S3Prefix",
                    "S3CompressionType" : "None"
                  }
                }
              }
            ],
            "ProcessingOutputConfig" : [
              {
                "OutputName" : "output",
                "S3OutputConfig" : {
                  "S3Uri" : "s3://your-output-bucket/path/to/output",
                  "S3UploadMode" : "EndOfJob",
                  "LocalPath" : "/opt/ml/processing/output",
                  "S3UploadFormat" : "Tree"
                }
              }
            ],
            "ProcessingResources" : {
              "ClusterConfig" : {
                "InstanceCount" : 1,
                "InstanceType" : "ml.m5.xlarge",
                "VolumeSizeInGB" : 30
              }
