resource "aws_instance" "al2_latest" {
  ami                    = data.aws_ami.amazon_linux_2.id
  instance_type          = "t3.large" # 2 vCPUs and 2 GiB memory (adjust if needed for cores/threads)
  subnet_id              = aws_subnet.default.id # Replace with your subnet ID
  vpc_security_group_ids = [aws_security_group.default.id] # Replace with your SG ID

  tags = {
    Name = "AmazonLinux2-Latest"
  }
}

data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

resource "aws_subnet" "default" {
  vpc_id     = aws_vpc.default.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "DefaultSubnet"
  }
}

resource "aws_vpc" "default" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "DefaultVPC"
  }
}

resource "aws_security_group" "default" {
  name        = "default-sg"
  description = "Allow SSH inbound traffic"
  vpc_id      = aws_vpc.default.id

  ingress {
    description = "SSH"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "DefaultSecurityGroup"
  }
}

