resource "aws_instance" "linux1" {
  ami           = "ami-0c55b159cbfafe1f0" # Latest Amazon Linux 2 AMI (us-east-1)
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.private_a.id
  security_groups = [aws_security_group.instance.name]
  associate_public_ip_address = false
  user_data     = <<-EOF
                  #!/bin/bash
                  yum update -y
                  yum install -y amazon-efs-utils
                  mkdir -p /mnt/efs
                  mount -t efs ${aws_efs_file_system.shared.id}:/ /mnt/efs
                  echo "${aws_efs_file_system.shared.id}:/ /mnt/efs efs _netdev,tls,iam 0 0" >> /etc/fstab
                  EOF
  tags = {
    Name = "linux-instance-1"
  }
}

