resource "aws_dynamodb_table" "low_latency" {
  name           = "LowLatencyCache"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "CacheKey"

  attribute {
    name = "CacheKey"
    type = "S"
  }

  # Enable DynamoDB Accelerator (DAX) for reduced latency
  server_side_encryption {
    enabled     = true
  }

  # Optional: Enable point-in-time recovery for backup purposes
  point_in_time_recovery {
    enabled = true
  }

  # Optional: Enable auto-scaling to handle variable workloads
  auto_scaling {
    target_utilization {
      target_value = 70.0
      attribute    = "ReadCapacityUnits"
    }
    auto_scaling_read {
      min_capacity = 5
      max_capacity = 100
    }
    auto_scaling_write {
      min_capacity = 5
      max_capacity = 100
    }
  }
}

# Optional: Create a DAX cluster for further reduced latency
resource "aws_dax_cluster" "example" {
  cluster_name    = "LowLatencyDAXCluster"
  node_type       = "dax.r4.large"
  replication_factor = 1
  parameter_group_name = "default.daxcluster"

  # Enable encryption at rest
  encryption_at_rest {
    enabled = true
  }

  # Optional: Enable auto-scaling for DAX cluster
  auto_scaling {
    min_partitions_per_node = 1
    max_partitions_per_node = 10
  }

  # Associate the DAX cluster with the DynamoDB table
  depends_on = [aws_dynamodb_table.low_latency]
}

