  deletion_window_in_days = 30
  enable_key_rotation     = true
}

resource "aws_s3_bucket" "msk_logs" {
  bucket = "msk-logs-${random_id.suffix.hex}"
}

resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/kafka/msk-cluster-logs"
  retention_in_days = 7
}

resource "aws_kinesis_firehose_delivery_stream" "msk_stream" {
  name        = "msk-delivery-stream-${random_id.suffix.hex}"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_s3.arn
    bucket_arn = aws_s3_bucket.ms_logs.arn
    prefix     = "kafka-logs/"
    buffering_hints {
      size    = 5
      interval = 300
    }
  }
}

resource "aws_iam_role" "firehose_s3" {
  name = "firehose-s3-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "firehose.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy" "firehose_s3" {
  name = "firehose-s3-policy"
  role = aws_iam_role.firehose_s3.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect = "Allow"
      Action = [
        "s3:AbortMultipartUpload",
        "s3:GetBucketLocation",
        "s3:GetObject",
        "s3:ListBucket",
        "s3:PutObject"
      ]
      Resource = [
        aws_s3_bucket.ms_logs.arn,
        "${aws_s3_bucket.ms_logs.arn}/*"
      ]
    }]
  })
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-cluster-${random_id.suffix.hex}"
  kafka_version          = "3.4.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.t3.small"
    client_subnets  = ["subnet-12345678", "subnet-87654321", "subnet-fedcba98"]
    security_groups = [aws_security_group.msk.id]
  }

  encryption_info {
    encryption_in_transit {
      client_broker_encryption_type = "TLS_PLAINTEXT"
    }
    encryption_at_rest_kms_key_arns = [aws_kms_key.msk_key.arn]
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
    }
  }

  tags = {
    Environment = "dev"
  }
}

resource "aws_security_group" "msk" {
  name        = "msk-security-group-${random_id.suffix.hex}"
  description = "Allow inbound traffic to MSK brokers"

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

