resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "debezium-msk-${random_id.suffix.hex}"
  kafka_version          = "3.4.0" # or latest stable version
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = ["subnet-12345678", "subnet-87654321"] # Replace with actual subnets
    security_groups = [aws_security_group.msk.id]
  }

  configuration_info {
    arn      = "arn:aws:kafka:${var.region}:${data.aws_caller_identity.current.account_id}:cluster/${aws_msk_cluster.example.cluster_name}/configuration/3.4.0" # Replace with actual config ARN
    revision = 1
  }

  encryption_info {
    encryption_in_transit {
      client_broker_encrypted = true
    }
  }

  tags = {
    Name = "debezium-msk-cluster"
  }
}

resource "aws_security_group" "msk" {
  name        = "msk-security-group"
  description = "Allow MSK traffic"
  vpc_id      = "vpc-12345678" # Replace with actual VPC ID

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_s3_bucket" "connect_plugins" {
  bucket = "msk-connect-plugins-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_object" "debezium_plugin" {
  bucket = aws_s3_bucket.connect_plugins.bucket
  key    = "debezium.zip"
  source = "path/to/local/debezium.zip" # Replace with actual path
  etag   = filemd5("path/to/local/debezium.zip")
}

resource "aws_mskconnect_custom_plugin" "debezium" {
  name = "debezium-custom-plugin"
  content {
    s3 {
      bucket_arn = aws_s3_bucket.connect_plugins.arn
      file_key    = aws_s3_bucket_object.debezium_plugin.key
    }
  }
}

resource "aws_mskconnect_connector" "debezium_connector" {
  name = "debezium-connector-${random_id.suffix.hex}"
  kafka_cluster {
    kafka_cluster_arn = aws_msk_cluster.example.arn
    vpc {
      security_groups = [aws_security_group.msk.id]
      subnets         = ["subnet-12345678", "subnet-87654321"] # Replace with actual subnets
    }
  }
  custom_plugin {
    arn      = aws_mskconnect_custom_plugin.debezium.arn
    version  = "1.0.0" # Replace with actual version
  }
  connector_configuration {
    schema_registry_configs = "{"kafkaApiVersion":"2.6.0"}"
    connector_class         = "io.debezium.connector.mysql.MySqlConnector"
    tasks_max               = 1
    offset_storage_topic    = "debezium-offsets"
    offset_storage_topic_replication_factor = 1
    offset_topic_replication_factor = 1
    topics_pattern          = "dbserver1.*"
    database_hostname       = "your-database-host" # Replace with actual database hostname
    database_port           = 3306
    database_user           = "debezium"
    database_password       = "your-db-password" # Replace with actual password
  }
}
```

