}

data "aws_iam_policy_document" "kms_policy" {
  statement {
    sid    = "Enable IAM User Permissions"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }
    actions   = ["kms:*"]
    resources = ["*"]
  }
}

data "aws_caller_identity" "current" {}

resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/kafka/cluster/${aws_msk_cluster.ms_cluster.cluster_name}"
  retention_in_days = 7
}

resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket = "msk-logs-bucket-${random_id.suffix.hex}"
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-firehose-${random_id.suffix.hex}"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_s3_role.arn
    bucket_arn = aws_s3_bucket.msk_logs_bucket.arn
    prefix     = "msk-logs/"
    buffering_hints {
      size_in_mb   = 5
      interval_in_seconds = 300
    }
  }
}

resource "aws_iam_role" "firehose_s3_role" {
  name = "firehose-s3-role-${random_id.suffix.hex}"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "firehose.amazonaws.com"
      }
    }]
  })
}

