  bucket = "msk-logs-bucket-${random_id.suffix.hex}"
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-firehose-${random_id.suffix.hex}"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_s3_role.arn
    bucket_arn = aws_s3_bucket.msk_logs_bucket.arn
    prefix     = "msk-logs/"
    buffering_hints {
      size_in_mb   = 5
      interval_in_seconds = 300
    }
  }
}

resource "aws_iam_role" "firehose_s3_role" {
  name = "firehose-s3-role-${random_id.suffix.hex}"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "firehose.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose-s3-policy"
  role = aws_iam_role.firehose_s3_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect = "Allow"
      Action = [
        "s3:AbortMultipartUpload",
        "s3:GetBucketLocation",
        "s3:GetObject",
        "s3:ListBucket",
        "s3:PutObject"
      ]
      Resource = [
        aws_s3_bucket.msk_logs_bucket.arn,
        "${aws_s3_bucket.msk_logs_bucket.arn}/*"
      ]
    }]
  })
}

resource "aws_msk_cluster" "ms_cluster" {
  cluster_name           = "ms-cluster-${random_id.suffix.hex}"
  kafka_version          = "3.4.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.t3.small"
    client_subnets  = ["subnet-12345678", "subnet-87654321"] # Replace with your subnet IDs
    security_groups = [aws_security_group.ms_broker_sg.id]
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS_PLAINTEXT"
    }
    encryption_at_rest {
      kms_key_arn = aws_kms_key.msk_key.arn
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
    }
  }

  tags = {
    Environment = "dev"
  }
}

resource "aws_security_group" "ms_broker_sg" {
  name        = "ms-broker-sg-${random_id.suffix.hex}"
  description = "Security group for MSK brokers"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_s3_bucket_object" "debezium_plugin" {
  bucket = "msk-connect-plugins-${random_id.suffix.hex}"
  key    = "debezium.zip"
  source = "path/to/local/debezium.zip" # Replace with your local path
  etag   = filemd5("path/to/local/debezium.zip") # Replace with your local path
}

resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name = "debezium-plugin-${random_id.suffix.hex}"
  content {
    s3 {
      bucket_arn = aws_s3_bucket.ms_connect_plugins.arn
      file_key   = "debezium.zip"
    }
  }
}

resource "aws_s3_bucket" "ms_connect_plugins" {
  bucket = "msk-connect-plugins-${random_id.suffix.hex}"
}

resource "aws_mskconnect_connector" "example_connector" {
  name = "debezium-connector-${random_id.suffix.hex}"
  kafka_cluster {
    kafka_cluster_arn = aws_msk_cluster.ms_cluster.arn
    vpc {
