    min_ttl                = 0
    default_ttl            = 3600 # 1 hour
    max_ttl                = 86400 # 1 day (custom TTL for data expiration)
    compress               = true
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

