resource "random_id" "bucket_suffix" {
  byte_length = 4
}

resource "aws_s3_bucket" "source_bucket" {
  bucket = "source-bucket-${random_id.bucket_suffix.hex}"
  force_destroy = true
}

resource "aws_s3_bucket" "inventory_bucket" {
  bucket = "inventory-bucket-${random_id.bucket_suffix.hex}"
  force_destroy = true
}

resource "aws_s3_bucket_notification" "inventory_notification" {
  bucket = aws_s3_bucket.source_bucket.id

  lambda_function {
    lambda_function_arn = aws_lambda_function.csv_inventory_function.arn
    events              = ["s3:ObjectCreated:*"]
    filter_suffix       = ".csv"
  }

  depends_on = [aws_lambda_permission.allow_bucket]
}

resource "aws_lambda_function" "csv_inventory_function" {
  function_name = "generate-s3-inventory"
  runtime       = "python3.8"
  handler       = "lambda_function.lambda_handler"
  role          = aws_iam_role.lambda_exec.arn

  filename      = "data-processing.zip"
  source_code_hash = filebase64sha256("data-processing.zip")

  environment {
    variables = {
      INVENTORY_BUCKET = aws_s3_bucket.inventory_bucket.id
    }
  }
}

resource "aws_iam_role" "lambda_exec" {
  name = "s3-inventory-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "s3_access_policy" {
  name = "s3-access-policy"
  role = aws_iam_role.lambda_exec.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:ListBucket",
          "s3:GetBucketLocation"
        ],
        Resource = aws_s3_bucket.source_bucket.arn
      },
      {
        Effect = "Allow",
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:DeleteObject"
        ],
        Resource = "${aws_s3_bucket.inventory_bucket.arn}/*"
      }
    ]
  })
}

resource "aws_lambda_permission" "allow_bucket" {
  statement_id  = "AllowExecutionFromS3Bucket"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.csv_inventory_function.arn
  principal     = "s3.amazonaws.com"
  source_arn    = aws_s3_bucket.source_bucket.arn
}

resource "aws_cloudwatch_event_rule" "weekly_inventory" {
  name                = "weekly-s3-inventory"
  description         = "Fires weekly to generate S3 inventory report"
  schedule_expression = "cron(0 12 ? * MON *)" # Runs every Monday at 12:00 UTC
}

resource "aws_cloudwatch_event_target" "inventory_lambda" {
  rule      = aws_cloudwatch_event_rule.weekly_inventory.name
  target_id = "sendInventory"
  arn       = aws_lambda_function.csv_inventory_function.arn
}

resource "aws_lambda_permission" "allow_cloudwatch" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.csv_inventory_function.arn
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.weekly_inventory.arn
}

