}

resource "aws_codebuild_source_version" "github_source" {
  identifier    = "autograder-github-source"
  cache_type    = "LOCAL_CACHE"
  local_cache_mode = "LOCAL_CACHE"
  local_cache_path = "/tmp/codebuild"
}

resource "aws_codebuild_project" "autograder" {
  name          = "autograder-${random_id.suffix.hex}"
  description   = "Autograder for CS class"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_LARGE"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = true

    environment_variable {
      name  = "INPUT_BUCKET"
      value = aws_s3_bucket.input_bucket.bucket
    }

    environment_variable {
      name  = "OUTPUT_BUCKET"
      value = aws_s3_bucket.output_bucket.bucket
    }

    environment_variable {
      name  = "GITHUB_REPO"
      value = "your-students-repo-url" # Replace with actual repo URL
    }
  }

  source {
    type      = "GITHUB"
    location  = "your-students-repo-url" # Replace with actual repo URL
    git_clone_depth = 1
  }

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  timeout_in_minutes = 60
}

resource "aws_codebuild_source_credential" "github_credential" {
  identifier = "autograder-github-credential"
  token      = "your-github-personal-access-token" # Replace with actual token
}

