  function_name = "trigger-autograder-${random_id.suffix.hex}"
  role          = aws_iam_role.codebuild_role.arn
  handler       = "index.handler"
  runtime       = "nodejs14.x"
  filename      = "data.zip" # Replace with actual zip file containing Lambda function

  environment {
