resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_s3_bucket" "student_submissions" {
  bucket = "autograder-student-submissions-${random_id.suffix.hex}"
  force_destroy = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "aws_s3_bucket" "results" {
  bucket = "autograder-results-${random_id.suffix.hex}"
  force_destroy = true

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_s3_access" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_iam_role_policy_attachment" "codebuild_ssm_access" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMReadOnlyAccess"
}

resource "aws_codebuild_project" "autograder" {
  name          = "autograder-${random_id.suffix.hex}"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "INPUT_BUCKET"
      value = aws_s3_bucket.student_submissions.bucket
    }

    environment_variable {
      name  = "OUTPUT_BUCKET"
      value = aws_s3_bucket.results.bucket
    }

    environment_variable {
      name  = "GITHUB_REPO"
      value = "your-students-repo-url" # Replace with actual repo URL
    }
  }

  source {
    type = "GITHUB"
    location = "https://github.com/your-org/your-repo.git" # Replace with actual repo URL
  }

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  build_timeout = 600 # 10 minutes

  tags = {
    Name = "Autograder"
  }
}

resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/autograder-${random_id.suffix.hex}"
  retention_in_days = 7
}

resource "aws_lambda_function" "trigger_autograder" {
  function_name = "trigger-autograder-${random_id.suffix.hex}"
  role          = aws_iam_role.codebuild_role.arn
  handler       = "index.handler"
  runtime       = "nodejs14.x"
  filename      = "data.zip" # Replace with actual zip file containing Lambda function

  environment {
    variable = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograder.name
      INPUT_BUCKET      = aws_s3_bucket.student_submissions.bucket
      OUTPUT_BUCKET     = aws_s3_bucket.results.bucket
    }
  }
}

resource "aws_lambda_permission" "allow_codebuild" {
  statement_id  = "AllowExecutionFromCodeBuild"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.trigger_autograder.function_name
  principal     = "codebuild.amazonaws.com"
  source_arn    = aws_codebuild_project.autograder.arn
}

resource "aws_s3_bucket_notification" "student_submissions_notification" {
  bucket = aws_s3_bucket.student_submissions.id

  lambda_function {
    lambda_function_arn = aws_lambda_function.trigger_autograder.arn
    events              = ["s3:ObjectCreated:*"]
    filter_suffix       = ".zip" # Trigger on .zip files (student submissions)
  }

  depends_on = [aws_lambda_permission.allow_codebuild]
}
