# CodeBuild project for running the autograder
resource "aws_codebuild_project" "autograder" {
  name          = "autograder-${random_id.suffix.hex}"
  description   = "Autograder for CS class"
  build_timeout = "60"

  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = true

    environment_variable {
      name  = "STUDENT_SUBMISSIONS_BUCKET"
      value = aws_s3_bucket.student_submissions.bucket
    }

    environment_variable {
      name  = "AUTOGRADER_RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }

    environment_variable {
      name  = "VPC_ID"
      value = aws_vpc.autograder_vpc.id
    }

    environment_variable {
      name  = "PRIVATE_SUBNET_ID"
      value = aws_subnet.private_subnet.id
    }

    environment_variable {
      name  = "SECURITY_GROUP_ID"
      value = aws_security_group.autograder_sg.id
    }
  }

  source {
    type      = "CODECOMMIT"
    location  = "https://git-codecommit.us-east-1.amazonaws.com/v1/repos/autograder"
    git_clone_depth = 1
  }

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE"]
  }
}

# CodeBuild buildspec file
resource "aws_s3_bucket_object" "buildspec" {
  bucket = aws_s3_bucket.student_submissions.bucket
  key    = "buildspec.yml"
  content = <<-EOT
version: 0.2
phases:
  install:
    runtime-versions:
      python: 3.8
    commands:
      - echo "Installing dependencies..."
      - pip install --upgrade pip
      - pip install pytest
  pre_build:
    commands:
      - echo "Downloading student submission..."
      - aws s3 cp s3://${aws_s3_bucket.student_submissions.bucket}/submission.zip .
      - unzip submission.zip
      - echo "Setting up isolated environment..."
      - docker run -d --network=none --name autograder-container amazonlinux:latest
  build:
    commands:
      - echo "Running tests in isolated environment..."
      - docker exec autograder-container bash -c "cd student-submission && python3 -m pytest --tb=short"
      - echo "Storing results..."
      - docker cp autograder-container:/tmp/results s3://${aws_s3_bucket.autograder_results.bucket}/results_${CODEBUILD_BUILD_ID}.zip
  post_build:
    commands:
      - echo "Cleaning up..."
      - docker rm -f autograder-container
      - aws s3 rm s3://${aws_s3_bucket.student_submissions.bucket}/submission.zip
EOT
}

# Lambda function to trigger CodeBuild
resource "aws_iam_role" "lambda_role" {
  name = "autograder-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_codebuild_trigger" {
  name = "autograder-lambda-codebuild-trigger"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "codebuild:StartBuild"
        ],
        Resource = [
          aws_codebuild_project.autograder.arn
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_lambda_function" "trigger_autograder" {
  function_name = "trigger-autograder-${random_id.suffix.hex}"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.lambda_handler"
  runtime       = "python3.8"
  timeout       = 300

  filename      = "data/autograder_trigger.zip"
  source_code_hash = filebase64sha256("data/autograder_trigger.zip")

  environment {
    variables = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograder.name
    }
  }
}

# API Gateway to trigger the Lambda function
resource "aws_api_gateway_rest_api" "autograder_api" {
  name = "autograder-api"
}

resource "aws_api_gateway_resource" "trigger" {
  rest_api_id = aws_api_gateway_rest_api.autograder_api.id
  parent_id   = aws_api_gateway_rest_api.autograder_api.root_resource_id
  path_part   = "trigger"
}

resource "aws_api_gateway_method" "trigger_method" {
  rest_api_id   = aws_api_gateway_rest_api.autograder_api.id
  resource_id   = aws_api_gateway_resource.trigger.id
  http_method   = "POST"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "trigger_integration" {
  rest_api_id = aws_api_gateway_rest_api.autograder_api.id
  resource_id = aws_api_gateway_resource.trigger.id
  http_method = aws_api_gateway_method.trigger_method.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.trigger_autograder.invoke_arn
}

resource "aws_lambda_permission" "apigw_lambda" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.trigger_autograder.function_name
  principal     = "apigateway.amazonaws.com"

  source_arn = "${aws_api_gateway_rest_api.autograder_api.execution_arn}/*/*"
}

resource "aws_api_gateway_deployment" "autograder_deployment" {
  depends_on = [aws_api_gateway_integration.trigger_integration]
  rest_api_id = aws_api_gateway_rest_api.autograder_api.id
  stage_name  = "prod"
}

