    Name = "autograder-nat-eip"
  }
}

resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.private_subnet.id
  tags = {
    Name = "autograder-nat-gw"
  }
}

resource "aws_security_group" "autograder_sg" {
  name        = "autograder-sg"
  description = "Allow SSH and internal traffic"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# S3 bucket for storing student submissions and results
