  vpc_id     = aws_vpc.autograder_vpc.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "autograder-subnet-${random_id.suffix.hex}"
  }
}

resource "aws_security_group" "autograder_sg" {
  name        = "autograder-security-group-${random_id.suffix.hex}"
  description = "Allow CodeBuild traffic within VPC"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "autograder-sg-${random_id.suffix.hex}"
  }
}

resource "aws_s3_bucket" "student_code_bucket" {
  bucket = "student-code-autograder-${random_id.suffix.hex}"
  force_destroy = true

  tags = {
    Name = "student-code-autograder-${random_id.suffix.hex}"
  }
}

resource "aws_s3_bucket_public_access_block" "student_code_bucket_block" {
  bucket = aws_s3_bucket.student_code_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_service_role" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSCodeBuildServiceRole"
}

resource "aws_iam_role_policy" "codebuild_s3_access" {
  name = "autograder-codebuild-s3-access-${random_id.suffix.hex}"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Resource = [
          aws_s3_bucket.student_code_bucket.arn,
          "${aws_s3_bucket.student_code_bucket.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project-${random_id.suffix.hex}"
  description   = "Autograder for CS class"
  service_role  = aws_iam_role.codebuild_role.arn

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image          = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type           = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "BUCKET_NAME"
      value = aws_s3_bucket.student_code_bucket.bucket
    }

    environment_variable {
      name  = "VPC_ID"
      value = aws_vpc.autograder_vpc.id
    }

    environment_variable {
      name  = "SUBNET_ID"
      value = aws_subnet.autograder_subnet.id
    }

    environment_variable {
      name  = "SECURITY_GROUP_ID"
      value = aws_security_group.autograder_sg.id
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/students/cs-class-autograder"
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  build_timeout = 60

  tags = {
    Name = "autograder-project-${random_id.suffix.hex}"
  }
}

resource "aws_vpc_endpoint" "s3" {
  vpc_id            = aws_vpc.autograder_vpc.id
  service_name      = "com.amazonaws.us-east-1.s3"
  vpc_endpoint_type = "Gateway"
}

