  vpc_id            = aws_vpc.autograder_vpc.id
  service_name      = "com.amazonaws.us-east-1.codebuild"
  vpc_endpoint_type = "Interface"
  private_dns_enabled = true

  security_group_ids = [aws_security_group.autograder_sg.id]

  subnet_ids = [aws_subnet.autograder_subnet.id]
}

resource "aws_vpc_endpoint_route_table_association" "s3" {
  vpc_endpoint_id = aws_vpc_endpoint.s3.id
  route_table_id = aws_vpc.autograder_vpc.main_route_table_id
