resource "aws_iam_role" "eventbridge_role" {
  name = "eventbridge-code-execution-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "events.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "eventbridge_policy" {
  name        = "eventbridge-code-execution-policy-${random_id.suffix.hex}"
  description = "Policy for EventBridge to execute code"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "*"
      },
      {
        Effect = "Allow",
        Action = [
          "lambda:InvokeFunction"
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eventbridge_attachment" {
  role       = aws_iam_role.eventbridge_role.name
  policy_arn = aws_iam_policy.eventbridge_policy.arn
}

resource "aws_cloudwatch_event_rule" "daily_schedule" {
  name                = "daily-code-execution-${random_id.suffix.hex}"
  schedule_expression = "cron(0 7 * * ? *)" # Runs at 7 UTC every day
}

resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_schedule.name
  target_id = "trigger-lambda-function"
  arn       = aws_lambda_function.example.arn
}

resource "aws_lambda_function" "example" {
  function_name = "daily-code-execution-${random_id.suffix.hex}"
  runtime       = "python3.9"
  handler       = "index.lambda_handler"
  role          = aws_iam_role.eventbridge_role.arn

  filename      = "lambda_function.zip" # Replace with your lambda deployment package
  source_code_hash = filebase64sha256("lambda_function.zip")

  environment {
    variables = {
      LOG_GROUP_NAME = "/aws/lambda/${aws_cloudwatch_event_rule.daily_schedule.name}"
    }
  }
}
