    principals {
      type        = "AWS"
      identifiers = [aws_cloudfront_origin_access_identity.oai.iam_arn]
    }
  }
}

resource "aws_cloudfront_distribution" "video_streaming" {
  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"
  aliases             = ["streaming.example.com"]

  origin {
    domain_name = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.video_content.id}"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.oai.cloudfront_access_identity_path
    }
  }

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_content.id}"

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
    # For custom domain, uncomment and configure below:
    # acm_certificate_arn      = "arn:aws:acm:us-east-1:123456789012:certificate/xxxxxx-xxxx-xxxx-xxxx-xxxxxxxx"
    # ssl_support_method       = "sni-only"
  }

  price_class = "PriceClass_All"
}

resource "aws_route53_zone" "primary" {
  name = "example.com"
}

resource "aws_route53_record" "streaming" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "streaming.example.com"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_streaming.domain_name
    zone_id                = aws_cloudfront_distribution.video_streaming.hosted_zone_id
    evaluate_target_health = false
  }
}

resource "aws_cloudfront_cache_policy" "video_streaming" {
  name        = "video-streaming-cache-policy"
  default_ttl = 3600
  max_ttl     = 86400
  min_ttl     = 0
  parameters_in_cache_key {
    cookies_config {
      cookie_behavior = "none"
    }
    query_strings_config {
      query_string_behavior = "none"
    }
  }
}

resource "aws_cloudfront_response_headers_policy" "security_headers" {
  name = "security-headers-policy"

  security_headers_config {
    frame_options {
      frame_option = "DENY"
    }
    referrer_policy {
      referrer_policy = "same-origin"
    }
    content_type_options {
      override = true
    }
    xss_protection {
      protection = true
      mode_block  = true
    }
    strict_transport_security {
      access_control_max_age_sec  = 31536000
      include_subdomains          = true
      override                     = true
    }
    content_security_policy {
      content_security_policy = "default-src 'self'; script-src 'self'; object-src 'none'; frame-src 'none';"
      override                = true
    }
  }
}

resource "aws_cloudfront_distribution" "video_streaming_updated" {
  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"
  aliases             = ["streaming.example.com"]

  origin {
    domain_name = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.video_content.id}"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.oai.cloudfront_access_identity_path
    }
  }

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_content.id}"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    cache_policy_id = aws_cloudfront_cache_policy.video_streaming.id
    response_headers_policy_id = aws_cloudfront_response_headers_policy.security_headers.id
    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
