    # ssl_support_method       = "sni-only"
  }

  price_class = "PriceClass_All"
}

resource "aws_cloudfront_function" "video_streaming_origin_request" {
  name    = "video-streaming-origin-request"
  runtime = "cloudfront-js-1.0"
  publish = true

  code = <<-EOF
    function handler(event) {
      var request = event.request;
      request.headers["origin"] = { value: "https://streaming.example.com" };
      return request;
    }
  EOF
}

