  certificate_arn   = "arn:aws:acm:us-east-1:123456789012:certificate/xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx" # Replace with your ACM certificate ARN

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.video.arn
  }
}

resource "aws_instance" "video_server" {
  count         = 3
  ami           = "ami-0c55b159cbfafe1f0" # Amazon Linux 2 AMI (replace with your preferred AMI)
  instance_type = "t3.medium"
  subnet_id     = element(aws_subnet.public[*].id, count.index % 2)
  vpc_security_group_ids = [aws_security_group.server.id]

  user_data = <<-EOF
              #!/bin/bash
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Video Streaming Server ${count.index + 1}</h1>" > /var/www/html/index.html
              EOF

  tags = {
    Name = "video-streaming-server-${count.index + 1}"
  }
}

resource "aws_lb_target_group_attachment" "video_server" {
  count            = 3
  target_group_arn = aws_lb_target_group.video.arn
  target_id        = aws_instance.video_server[count.index].id
  port             = 8080
}
