  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust based on your VPC CIDR or use security group references
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_db_parameter_group" "postgres" {
  name        = "postgres-custom-params"
  family      = "postgres13"
  description = "Custom PostgreSQL parameter group"

  parameter {
    name  = "log_min_duration_statement"
    value = "1000"
  }

  parameter {
    name  = "max_connections"
    value = "200"
  }
}

resource "aws_db_instance" "postgres" {
  identifier             = "postgres-${random_id.suffix.hex}"
  allocated_storage      = 20
  storage_type           = "gp2"
  engine                 = "postgres"
  engine_version         = "13.4"
  instance_class         = "db.t3.medium"
  db_name                = "postgresdb"
  username               = "postgresadmin"
  password               = random_password.db.result
  parameter_group_name   = aws_db_parameter_group.postgres.name
  skip_final_snapshot    = false
  final_snapshot_identifier = "pgsnapshot"
  multi_az               = true
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.private_subnets.name
  kms_key_id             = aws_kms_key.db_key.arn
  storage_encrypted      = true
  publicly_accessible    = false
}
```

