resource "aws_subnet" "private_subnet_1" {
  vpc_id            = aws_vpc.aurora_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "aurora-private-subnet-1"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.aurora_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "aurora-private-subnet-2"
  }
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.aurora_vpc.id
  tags = {
    Name = "aurora-igw"
  }
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.aurora_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
  tags = {
    Name = "aurora-public-rt"
  }
}

resource "aws_route_table_association" "public_subnet_1" {
  subnet_id      = aws_subnet.private_subnet_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "public_subnet_2" {
  subnet_id      = aws_subnet.private_subnet_2.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_security_group" "rds_sg" {
  name        = "aurora-rds-sg"
  description = "Allow inbound traffic to RDS"
  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-rds-sg"
  }
}

resource "aws_iam_role" "rds_proxy_role" {
  name = "aurora-rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_proxy_attachment" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSProxyServiceRole"
}

resource "aws_secretsmanager_secret" "db_credentials" {
  name        = "aurora-mysql-${random_id.suffix.hex}"
  description = "Credentials for Aurora MySQL"
}

resource "aws_secretsmanager_secret_version" "db_credentials_version" {
  secret_id     = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "adminuser"
    password = random_password.db.result
  })
}

resource "random_password" "db" {
  length  = 32
  special = true
}

resource "aws_db_proxy" "aurora_proxy" {
  name                   = "aurora-mysql-proxy-${random_id.suffix.hex}"
  role_arn               = aws_iam_role.rds_proxy_role.arn
  require_tls            = true
  debug_logging          = false
  idle_client_timeout    = 1800
  max_connections        = 200
  secrets_arn            = aws_secretsmanager_secret.db_credentials.arn
  vpc_subnet_ids         = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  tags = {
    Name = "aurora-mysql-proxy"
  }
}

resource "aws_rds_cluster" "aurora_mysql" {
  cluster_identifier      = "aurora-mysql-cluster-${random_id.suffix.hex}"
  engine                  = "aurora-mysql"
  engine_mode             = "provisioned"
  database_name           = "auroradb"
  master_username         = "adminuser"
  master_password         = random_password.db.result
  backup_retention_period = 7
  preferred_backup_window = "07:00-09:00"
  storage_encrypted       = true
  skip_final_snapshot     = true
  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  db_subnet_group_name    = aws_db_subnet_group.private_subnets.name
  enable_http_endpoint    = false
}

resource "aws_db_subnet_group" "private_subnets" {
  name       = "aurora-mysql-subnet-group"
  subnet_ids = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
  tags = {
    Name = "aurora-mysql-subnet-group"
  }
}

resource "aws_db_instance" "aurora_writer" {
  identifier             = "aurora-mysql-writer-${random_id.suffix.hex}"
  cluster_identifier     = aws_rds_cluster.aurora_mysql.id
  engine                 = aws_rds_cluster.aurora_mysql.engine
  engine_version         = aws_rds_cluster.aurora_mysql.engine_version
  instance_class         = "db.r5.large"
  db_subnet_group_name   = aws_db_subnet_group.private_subnets.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = false
  skip_final_snapshot    = true
  depends_on             = [aws_rds_cluster.aurora_mysql]
}

