}

resource "aws_vpc" "rds_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "rds-aurora-vpc"
  }
}

resource "aws_subnet" "private_subnet_1" {
  vpc_id            = aws_vpc.rds_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "private-subnet-1"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.rds_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "private-subnet-2"
  }
}

resource "aws_subnet" "private_subnet_3" {
  vpc_id            = aws_vpc.rds_vpc.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1c"
  tags = {
    Name = "private-subnet-3"
  }
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.rds_vpc.id
  tags = {
    Name = "main"
  }
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.rds_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public_subnet_1" {
  subnet_id      = aws_subnet.private_subnet_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "public_subnet_2" {
  subnet_id      = aws_subnet.private_subnet_2.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "public_subnet_3" {
  subnet_id      = aws_subnet.private_subnet_3.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_security_group" "rds_sg" {
  name        = "rds-aurora-sg"
  description = "Allow inbound traffic to RDS"
  vpc_id      = aws_vpc.rds_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_proxy_policy" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSEnhancedMonitoringRole"
}

resource "aws_rds_cluster" "aurora_mysql" {
  cluster_identifier      = "aurora-mysql-cluster-${random_id.suffix.hex}"
  engine                  = "aurora-mysql"
  engine_mode             = "provisioned"
  database_name           = "auroradb"
  master_username         = "admin"
  master_password         = random_password.db.result
  backup_retention_period = 7
  preferred_backup_window = "07:00-09:00"
  storage_encrypted       = true
  skip_final_snapshot     = false
  final_snapshot_identifier = "snapshot"
  db_subnet_group_name    = aws_db_subnet_group.private_subnets.name
  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  enable_http_endpoint    = true
  enable_global_write_forwarding = false
  enable_cloudwatch_logs_exports = ["error", "general", "slowquery"]
  iam_database_authentication_enabled = true
}

resource "aws_db_subnet_group" "private_subnets" {
  name       = "private-subnets"
  subnet_ids = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id, aws_subnet.private_subnet_3.id]
}

resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-mysql-credentials"
}

resource "aws_secretsmanager_secret_version" "db_credentials_version" {
  secret_id = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db.result
  })
}

resource "aws_rds_cluster_instance" "aurora_instance_1" {
  cluster_identifier = aws_rds_cluster.aurora_mysql.id
  instance_class     = "db.r5.large"
  engine             = aws_rds_cluster.aurora_mysql.engine
  db_subnet_group_name = aws_db_subnet_group.private_subnets.name
}

resource "aws_rds_cluster_instance" "aurora_instance_2" {
  cluster_identifier = aws_rds_cluster.aurora_mysql.id
  instance_class     = "db.r5.large"
  engine             = aws_rds_cluster.aurora_mysql.engine
  db_subnet_group_name = aws_db_subnet_group.private_subnets.name
}

resource "aws_rds_proxy" "aurora_proxy" {
  name                   = "aurora-mysql-proxy"
  engine_family          = "MYSQL"
  require_tls            = true
  secrets_arn            = aws_secretsmanager_secret.db_credentials.arn
  role_arn               = aws_iam_role.rds_proxy_role.arn
  vpc_subnet_ids         = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id, aws_subnet.private_subnet_3.id]
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  endpoint_identifier    = aws_rds_cluster.aurora_mysql.endpoint
  auth = {
    auth_scheme = "IAM"
    iam_auth_enabled = true
  }
}
```

