resource "aws_lightsail_instance" "compute" {
  availability_zone = "us-east-1a"
  bundle_id         = "nano_2_0" # 2 vCPUs, 2GB RAM
  key_pair_name     = "my-key-pair" # Replace with your key pair name
  name              = "lightsail-compute-${random_id.suffix.hex}"
  blueprint_id      = "ubuntu_22_04" # Ubuntu 22.04 LTS
  user_data         = <<-EOF
                    #!/bin/bash
                    sudo apt-get update
                    sudo apt-get install -y nfs-common
                    EOF
}

resource "aws_lightsail_storage" "storage" {
  name              = "lightsail-storage-${random_id.suffix.hex}"
  availability_zone = "us-east-1a"
  size              = 10 # 10GB storage
}

resource "aws_lightsail_storage_connection" "connection" {
  instance_name = aws_lightsail_instance.compute.name
  storage_name  = aws_lightsail_storage.storage.name
}

resource "aws_lightsail_disk_attachment" "disk_attachment" {
  instance_name = aws_lightsail_instance.compute.name
  disk_name     = aws_lightsail_storage.storage.name
  mount_path    = "/mnt/storage"
}

resource "null_resource" "mount_disk" {
  depends_on = [aws_lightsail_disk_attachment.disk_attachment]

  connection {
    type        = "ssh"
    user        = "ubuntu"
    private_key = file("~/.ssh/my-key-pair.pem") # Replace with your private key path
    host        = aws_lightsail_instance.compute.public_ip_address
  }

  provisioner "remote-exec" {
    inline = [
      "sudo mkdir -p /mnt/storage",
      "sudo mount -t nfs4 -o nfsvers=4.1,rsize=1048576,wsize=1048576,hard,timeo=600,retrans=2,noresvport ${aws_lightsail_storage.storage.arn}:/ /mnt/storage",
      "sudo chmod -R 777 /mnt/storage"
    ]
  }
}

