resource "aws_lightsail_distribution" "cdn" {
  domain_name = "example.com" # Replace with your desired domain name
  origin {
    domain = aws_s3_bucket.origin_bucket.bucket_regional_domain_name
    origin_path = "" # Optional: Path prefix for the origin
    custom_origin_config {
      http_port = 80
      https_port = 443
      origin_protocol_policy = "https-only"
      origin_ssl_protocols = ["TLSv1.2"]
    }
  }
  enabled = true
  aliases {
    alias = "cdn.example.com" # Replace with your desired CNAME
  }
  default_root_object = "index.html"
  price_plan = "cdn" # Lightsail CDN price plan
  viewer_protocol_policy = "redirect-to-https"
  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }
}

resource "aws_s3_bucket" "origin_bucket" {
  bucket = "example-origin-bucket" # Replace with your desired bucket name
  acl    = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "aws_s3_bucket_public_access_block" "origin_bucket" {
  bucket = aws_s3_bucket.origin_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_lightsail_distribution_cache_policy" "cdn_cache_policy" {
  distribution_id = aws_lightsail_distribution.cdn.id
  cache_policy {
    default_ttl       = 3600
    max_ttl           = 86400
    min_ttl           = 60
    forwarded_values {
      query_string = true
      cookies {
        forward = "none"
      }
    }
  }
}

resource "aws_lightsail_distribution_viewer_access_logging" "cdn_logging" {
  distribution_id = aws_lightsail_distribution.cdn.id
  enabled         = true
  bucket          = aws_s3_bucket.log_bucket.id
  prefix          = "cdn-logs/"
}

resource "aws_s3_bucket" "log_bucket" {
  bucket = "example-cdn-logs-bucket" # Replace with your desired bucket name for logs
  acl    = "log-delivery-write"
}

