data "aws_iam_policy_document" "glacier_vault_policy" {
  statement {
    actions   = ["s3:PutObject"]
    resources = ["${aws_s3_bucket.glacier_vault.arn}/*"]

    principals {
      type        = "Service"
      identifiers = ["glacier.amazonaws.com"]
    }

    condition {
      test     = "StringEquals"
      variable = "s3:x-amz-acl"
      values   = ["bucket-owner-full-control"]
    }
  }

  statement {
    actions   = ["s3:GetObjectVersion"]
    resources = ["${aws_s3_bucket.glacier_vault.arn}/*"]

    principals {
      type        = "Service"
      identifiers = ["glacier.amazonaws.com"]
    }
  }
}

resource "aws_dlm_lifecycle_policy" "glacier_policy" {
  policy_name = "glacier-transition-policy-${random_id.vault_suffix.hex}"
  schedule {
    name    = "transition-to-glacier"
    copy_action {
      destination = aws_s3_bucket.glacier_vault.arn
      sse_algorithm = "AES256"
    }
    transition_action {
      days        = 90
      storage_class = "GLACIER"
    }
  }
  application self_managed {
    events = ["S3ObjectCreatedPut", "S3ObjectCreatedPost", "S3ObjectCreatedCopy"]
  }
}

resource "aws_dlm_protection" "glacier_protection" {
  arn         = aws_dlm_lifecycle_policy.glacier_policy.arn
  name        = "glacier-protection-${random_id.vault_suffix.hex}"
  resource_arns = [aws_s3_bucket.glacier_vault.arn]
}

