resource "aws_s3_bucket_notification" "glacier_vault_notification" {
  bucket = aws_s3_bucket.glacier_vault.id

  lambda_function {
    lambda_function_arn = aws_lambda_function.glacier_notification.arn
    events              = ["s3:ObjectRemoved:*", "s3:ObjectRestore:*"]
    filter_suffix       = ".glacier"
  }

  depends_on = [aws_lambda_permission.allow_bucket]
}

resource "aws_cloudwatch_log_group" "glacier_notification_log" {
  name              = "/aws/lambda/glacier-notification"
  retention_in_days = 7
}

resource "aws_lambda_function" "glacier_notification" {
  function_name = "glacier-notification-${random_id.vault_suffix.hex}"
  runtime       = "python3.8"
  handler       = "lambda_function.lambda_handler"
  role          = aws_iam_role.lambda_exec.arn
  s3_bucket     = aws_s3_bucket.lambda_code_bucket.name
  s3_key        = "glacier_notification.zip"
  environment {
    variables = {
      VAULT_NAME = aws_s3_bucket.glacier_vault.id
    }
  }
}

resource "aws_iam_role" "lambda_exec" {
  name = "glacier_notification_lambda_exec"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_s3_access" {
  name = "glacier_notification_lambda_s3_access"
  role = aws_iam_role.lambda_exec.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:DeleteObject",
          "s3:ListBucket"
        ],
        Resource = [
          aws_s3_bucket.glacier_vault.arn,
          "${aws_s3_bucket.glacier_vault.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "glacier:InitiateJob",
          "glacier:AbortJob",
          "glacier:DescribeJob",
          "glacier:ListJobs",
          "glacier:GetJobOutput",
          "glacier:UploadArchive",
          "glacier:DeleteArchive"
        ],
        Resource = "*"
      }
    ]
  })
}

