data "aws_iam_policy_document" "glacier_vault_policy" {
  statement {
    sid    = "AllowS3GlacierAccess"
    effect = "Allow"

    principals {
      type        = "AWS"
      identifiers = ["*"]
    }

    actions = [
      "s3:PutObject",
      "s3:GetObject",
      "s3:DeleteObject",
      "s3:ListBucket"
    ]

    resources = [
      "arn:aws:s3:::your-bucket-name/*",
      "arn:aws:s3:::your-bucket-name"
    ]
  }
}

resource "aws_s3_bucket" "glacier_bucket" {
  bucket = "your-glacier-bucket-name-${random_id.suffix.hex}"
}

resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_s3_bucket_versioning" "glacier_bucket_versioning" {
  bucket = aws_s3_bucket.glacier_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "glacier_bucket_encryption" {
  bucket = aws_s3_bucket.glacier_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_glacier_vault" "example" {
  vault_name = "glacier-vault-${random_id.suffix.hex}"
}

resource "aws_glacier_vault_lock" "example" {
  vault_name = aws_glacier_vault.example.vault_name

  policy = <<POLICY
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "AllowS3GlacierAccess",
      "Effect": "Allow",
      "Principal": {
        "AWS": "*"
      },
      "Action": [
        "glacier:InitiateJob",
        "glacier:AbortJob",
        "glacier:ListJobs",
        "glacier:GetJobOutput",
        "glacier:GetJobParameters",
        "glacier:DescribeVault",
        "glacier:ListVaults",
        "glacier:PutVaultLock"
      ],
      "Resource": "arn:aws:glacier:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:vault/${aws_glacier_vault.example.vault_name}"
    }
  ]
}
POLICY
}

resource "aws_glacier_vault_policy" "example" {
  vault_name = aws_glacier_vault.example.vault_name
  policy     = data.aws_iam_policy_document.glacier_vault_policy.json
}

