}

resource "aws_s3_bucket_notification" "glacier_vault_notification" {
  bucket = aws_s3_bucket.glacier_vault.id

  lambda_function {
    lambda_function_arn = aws_lambda_function.glacier_notification.arn
    events              = ["s3:ObjectRestore:Complete"]
    filter_suffix       = ".glacier"
  }

  depends_on = [aws_lambda_permission.allow_lambda]
}

resource "aws_cloudwatch_event_rule" "glacier_retrieval_completed" {
  name        = "glacier-retrieval-completed-${random_id.vault_suffix.hex}"
  description = "Trigger for Glacier retrieval completion notification"
}

resource "aws_cloudwatch_event_target" "glacier_retrieval_target" {
  rule      = aws_cloudwatch_event_rule.glacier_retrieval_completed.name
  target_id = "send-glacier-notification"
  arn       = aws_lambda_function.glacier_notification.arn
}

resource "aws_lambda_function" "glacier_notification" {
  function_name = "glacier-retrieval-notification-${random_id.vault_suffix.hex}"
  runtime       = "python3.8"
  handler       = "index.lambda_handler"
  role          = aws_iam_role.lambda_exec.arn

  s3_bucket = aws_s3_bucket.glacier_vault.bucket
  s3_key    = "lambda/glacier_notification_function.zip"

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.glacier_vault.bucket
    }
  }
}

resource "aws_iam_role" "lambda_exec" {
  name = "glacier-lambda-role-${random_id.vault_suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
