resource "aws_lb_listener" "cognito_auth" {
  load_balancer_arn = aws_lb.authenticate_cognito.arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = aws_acm_certificate.cognito_lb_cert.arn

  default_action {
    type = "authenticate-cognito"
    authenticate_cognito {
      user_pool_arn       = aws_cognito_user_pool.cognito_pool.arn
      user_pool_client_id = aws_cognito_user_pool_client.cognito_client.id
      user_pool_domain    = aws_cognito_user_pool_domain.cognito_domain.domain
      authentication_type = "ALLOW_USER_PASSWORD_AUTH"
