    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "target_sg" {
  name        = "authenticate-cognito-target-sg"
  description = "Security group for target instances"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.lb_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_lb_listener" "cognito_auth" {
  load_balancer_arn = aws_lb.authenticate_cognito.arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = aws_acm_certificate.cognito_lb_cert.arn

  default_action {
    type = "authenticate-cognito"
    authenticate_cognito {
      user_pool_arn       = aws_cognito_user_pool.cognito_pool.arn
      user_pool_client_id = aws_cognito_user_pool_client.cognito_client.id
      user_pool_domain    = aws_cognito_user_pool_domain.cognito_domain.domain
      authentication_type = "ALLOW_USER_PASSWORD_AUTH"
    }
  }
}

resource "aws_cognito_user_pool" "cognito_pool" {
  name = "authenticate-cognito-pool-${random_id.suffix.hex}"
}

resource "aws_cognito_user_pool_client" "cognito_client" {
  name         = "authenticate-cognito-client"
  user_pool_id = aws_cognito_user_pool.cognito_pool.id
  generate_secret = true
  allowed_oauth_flows = ["code"]
  allowed_oauth_scopes = ["openid", "profile", "email"]
  allowed_oauth_flows_user_pool_client = true
  explicit_auth_flows = ["ALLOW_USER_PASSWORD_AUTH", "ALLOW_REFRESH_TOKEN_AUTH"]
}

resource "aws_cognito_user_pool_domain" "cognito_domain" {
  domain       = "authenticate-cognito-domain-${random_id.suffix.hex}"
  user_pool_id = aws_cognito_user_pool.cognito_pool.id
}

resource "aws_acm_certificate" "cognito_lb_cert" {
